const body = $json.body || $json;

const options = body.data?.options || [];
const getOption = (name) => options.find(o => o.name === name)?.value || "";

const rawAcao = String(
  body.acao ||
  body.action ||
  getOption("acao") ||
  ""
).toLowerCase().trim();

const mapa = {
  hoje: "agenda_hoje",
  amanha: "agenda_amanha",
  "amanhã": "agenda_amanha",
  semana: "agenda_semana",
  dia: "agenda_dia",
  criar: "criar_evento",
  excluir: "excluir_evento",
  deletar: "excluir_evento",
  apagar: "excluir_evento",
  sincronizar: "sincronizar_agenda",
  sync: "sincronizar_agenda"
};

let acao = mapa[rawAcao] || "desconhecida";

// Compatibilidade com comando antigo por mensagem
const msgOriginal = String(body.mensagem || body.mensagemOriginal || "").trim();
const msg = msgOriginal
  .toLowerCase()
  .normalize("NFD")
  .replace(/[\u0300-\u036f]/g, "");

if (acao === "desconhecida" && msg) {
  if (msg.includes("excluir") || msg.includes("deletar") || msg.includes("apagar")) acao = "excluir_evento";
  else if (msg.includes("sincronizar") || msg.includes("sync") || msg.includes("importar")) acao = "sincronizar_agenda";
  else if (msg.includes("criar") || msg.includes("marcar") || msg.includes("agendar")) acao = "criar_evento";
  else if (msg.includes("semana")) acao = "agenda_semana";
  else if (msg.includes("amanha")) acao = "agenda_amanha";
  else if (msg.includes("hoje")) acao = "agenda_hoje";
  else if (msg.includes("dia")) acao = "agenda_dia";
}

return [
  {
    json: {
      origem: body.origem || "discord_slash_command",
      applicationId: body.applicationId || body.application_id || "",
      token: body.token || "",
      commandName: body.commandName || body.data?.name || "agenda",
      acao,
      acaoOriginal: rawAcao,
      titulo: body.titulo || getOption("titulo") || "",
      data: body.dataTexto || body.data || getOption("data") || "",
      hora: body.hora || getOption("hora") || "",
      email: body.email || getOption("email") || "",
      mensagem: msg,
      mensagemOriginal: msgOriginal,
      usuario: body.usuario || body.member?.user?.username || body.user?.username || "Usuário Discord",
      userId: body.userId || body.member?.user?.id || body.user?.id || "",
      canal: body.canal || body.channelId || body.channel_id || "",
      guildId: body.guildId || body.guild_id || "",
      recebidoEm: new Date().toISOString()
    }
  }
];

const texto = $json.mensagemOriginal || $json.mensagem || '';
let titulo = ($json.titulo || '').trim();
let data = ($json.data || '').trim();
let hora = ($json.hora || '').trim();
let email = ($json.email || '').trim().replace(/[<>,;]/g, '');

// Compatibilidade com formato antigo: !agenda criar Reunião | 12/06/2026 | 14:00 | email@cliente.com
if (!titulo || !data || !hora || !email) {
  const partes = texto.split('|').map(p => p.trim());
  if (partes.length >= 4) {
    titulo = partes[0].replace(/!agenda/gi, '').replace(/criar/gi, '').replace(/marcar/gi, '').replace(/agendar/gi, '').trim();
    data = partes[1];
    hora = partes[2];
    email = partes[3].trim().replace(/[<>,;]/g, '');
  }
}

if (!titulo || !data || !hora || !email) {
  return [{
    json: {
      ...$json,
      erro: true,
      resposta: '❌ Formato inválido. Use: /agenda acao:criar titulo:Reunião Cliente data:12/06/2026 hora:14:00 email:email@cliente.com'
    }
  }];
}

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

if (!emailRegex.test(email)) {
  return [{
    json: {
      ...$json,
      erro: true,
      resposta: `❌ E-mail inválido recebido: ${email}`
    }
  }];
}

const [dia, mes, ano] = data.split('/');
if (!dia || !mes || !ano || !hora.includes(':')) {
  return [{
    json: {
      ...$json,
      erro: true,
      resposta: '❌ Data ou hora inválida. Use data:12/06/2026 e hora:14:00'
    }
  }];
}

const inicio = `${ano}-${mes.padStart(2, '0')}-${dia.padStart(2, '0')}T${hora}:00-03:00`;
const fimDate = new Date(inicio);
fimDate.setHours(fimDate.getHours() + 1);
const fim = fimDate.toISOString();

return [{
  json: {
    ...$json,
    erro: false,
    titulo,
    data,
    hora,
    email,
    inicio,
    fim,
    descricao: `Evento criado pelo Bot Agenda NIC no Discord. Solicitante: ${$json.usuario || 'Discord'}`,
    resposta: `✅ Evento preparado:\nTítulo: ${titulo}\nData: ${data}\nHora: ${hora}\nConvidado: ${email}`
  }
}];

const now = new Date();
const start = new Date(now);
start.setHours(0,0,0,0);
const end = new Date(now);
end.setHours(23,59,59,999);
return [{ json: { ...$json, inicio: start.toISOString(), fim: end.toISOString(), periodo: 'hoje' } }];

const now = new Date();
const start = new Date(now);
start.setDate(start.getDate()+1);
start.setHours(0,0,0,0);
const end = new Date(start);
end.setHours(23,59,59,999);
return [{ json: { ...$json, inicio: start.toISOString(), fim: end.toISOString(), periodo: 'amanhã' } }];

const now = new Date();
const start = new Date(now);
start.setHours(0,0,0,0);
const end = new Date(now);
end.setDate(end.getDate()+7);
end.setHours(23,59,59,999);
return [{ json: { ...$json, inicio: start.toISOString(), fim: end.toISOString(), periodo: 'semana' } }];

const eventos = $input.all();

const appId = $('Interpretar Comando').first().json.applicationId;
const token = $('Interpretar Comando').first().json.token;

if (eventos.length === 0) {
  return [{
    json: {
      applicationId: appId,
      token,
      resposta: '📅 Nenhum evento encontrado para hoje.'
    }
  }];
}

let texto = '📅 Agenda de hoje:\n\n';

for (const item of eventos) {
  const ev = item.json;
  const titulo = ev.summary || 'Sem título';
  const inicioRaw = ev.start?.dateTime || ev.start?.date || ev.start;

  let horario = '';
  if (inicioRaw) {
    const d = new Date(inicioRaw);
    horario = d.toLocaleString('pt-BR', {
      timeZone: 'America/Sao_Paulo',
      hour: '2-digit',
      minute: '2-digit'
    });
  }

  texto += `• ${horario} - ${titulo}\n`;
}

return [{
  json: {
    applicationId: appId,
    token,
    resposta: texto
  }
}];

