        });
  }

  texto += `• ${horario} - ${titulo}\n`;
}

return [{
  json: {
    applicationId: appId,
    token,
    resposta: texto
  }
}];

return [
  {
    json: {
      applicationId: $("Interpretar Comando").first().json.applicationId,
      token: $("Interpretar Comando").first().json.token,
      resposta: `✅ Reunião criada no Google Agenda com sucesso!\n\n📌 ${$json.summary || "Evento criado"}`,
    },
  },
];

const texto = $json.mensagemOriginal || $json.mensagem || '';
let dataInformada = $json.data || '';

if (!dataInformada) {
  const match = texto.match(/(\d{2})\/(\d{2})\/(\d{4})/);
  if (match) dataInformada = `${match[1]}/${match[2]}/${match[3]}`;
}

const match = String(dataInformada).match(/(\d{2})\/(\d{2})\/(\d{4})/);

if (!match) {
  return [{
    json: {
      ...$json,
      erro: true,
      resposta: '❌ Informe a data assim: /agenda acao:dia data:12/06/2026'
    }
  }];
}

const dia = match[1];
const mes = match[2];
const ano = match[3];

const start = new Date(`${ano}-${mes}-${dia}T00:00:00-03:00`);
const end = new Date(`${ano}-${mes}-${dia}T23:59:59-03:00`);

return [{
  json: {
    ...$json,
    inicio: start.toISOString(),
    fim: end.toISOString(),
    periodo: `${dia}/${mes}/${ano}`
  }
}];

const eventos = $input.all();

const appId = $("Interpretar Comando").first().json.applicationId;
const token = $("Interpretar Comando").first().json.token;

if (eventos.length === 0) {
  return [{
    json: {
      applicationId: appId,
      token,
      resposta: '📅 Nenhum evento encontrado nesse período.\n\n✅ Agenda livre.'
    }
  }];
}

let texto = '📅 Horários encontrados:\n\n';

for (const item of eventos) {
  const ev = item.json;
  const titulo = ev.summary || ev.title || 'Sem título';

  const inicioRaw = ev.start?.dateTime || ev.start?.date || ev.start;
  const fimRaw = ev.end?.dateTime || ev.end?.date || ev.end;

  let horarioInicio = '';
  let horarioFim = '';

  if (inicioRaw) {
    const d = new Date(inicioRaw);
    horarioInicio = d.toLocaleTimeString('pt-BR', {
      timeZone: 'America/Sao_Paulo',
      hour: '2-digit',
      minute: '2-digit'
    });
  }

  if (fimRaw) {
    const d = new Date(fimRaw);
    horarioFim = d.toLocaleTimeString('pt-BR', {
      timeZone: 'America/Sao_Paulo',
      hour: '2-digit',
      minute: '2-digit'
    });
  }

  texto += `• ${horarioInicio} às ${horarioFim} - ${titulo}\n`;
}

return [{
  json: {
    applicationId: appId,
    token,
    resposta: texto
  }
}];

const hoje = new Date();

const inicio = new Date(hoje);
inicio.setHours(0, 0, 0, 0);

const fim = new Date(hoje);
fim.setMonth(fim.getMonth() + 12);
fim.setHours(23, 59, 59, 999);

return [{
