return agendas.map((calendarId) => ({
  json: {
    ...$json,
    calendarioOrigem: calendarId,
    inicio: $json.inicio,
    fim: $json.fim,
  },
}));

const eventos = $input.all();

return eventos
  .map((item) => {
    const ev = item.json;

    const inicio = ev.start?.dateTime || null;
    const fim = ev.end?.dateTime || null;

    if (!inicio || !fim) return null;

    return {
      json: {
        applicationId: $("Interpretar Comando").first().json.applicationId,
        token: $("Interpretar Comando").first().json.token,
        titulo: String(ev.summary || "Sem título").slice(0, 200),
        inicio,
        fim,
        descricao: `COPIA_NIC_ID_ORIGINAL:${ev.id}
ORIGEM:${ev.organizer?.displayName || ev.organizer?.email || "Agenda Compartilhada"}`,
        local: "",
        eventoOriginalId: ev.id,
      },
    };
  })
  .filter(Boolean);

const items = $input.all();
const criados = items.filter(item => !item.json.error).length;
const erros = items.filter(item => item.json.error).length;

return [{
  json: {
    applicationId: $("Interpretar Comando").first().json.applicationId,
    token: $("Interpretar Comando").first().json.token,
    resposta: `✅ Sincronização finalizada.\n\n📌 Eventos novos processados: ${items.length}\n✅ Criados: ${criados}\n⚠️ Com erro: ${erros}\n\nA agenda principal não foi alterada.`
  }
}];

const items = $input.all();

// Pega applicationId e token do primeiro item que tiver esses campos
const contexto =
  items.find(item => item.json.applicationId && item.json.token)?.json || {};

const novos = items.filter(
  (item) =>
    !item.json.id &&
    item.json.inicio &&
    item.json.fim &&
    item.json.titulo
);

if (novos.length === 0) {
  return [
    {
      json: {
        applicationId: contexto.applicationId || "",
        token: contexto.token || "",
        semNovos: true,
        resposta: "✅ Sincronização concluída. Nenhum evento novo para copiar.",
      },
    },
  ];
}

return novos.map((item) => ({
  json: {
    applicationId: item.json.applicationId || contexto.applicationId || "",
    token: item.json.token || contexto.token || "",
    titulo: item.json.titulo,
    inicio: item.json.inicio,
    fim: item.json.fim,
    descricao: item.json.descricao,
    local: item.json.local || "",
    eventoOriginalId: item.json.eventoOriginalId,
    semNovos: false,
  },
}));

const texto = $json.mensagemOriginal || $json.mensagem || "";

const termo = (
  $json.titulo ||
  texto
    .replace(/!agenda/gi, "")
    .replace(/excluir/gi, "")
    .replace(/deletar/gi, "")
    .replace(/apagar/gi, "")
).trim();

if (!termo) {
  return [{
    json: {
      ...$json,
      erro: true,
      resposta: "❌ Informe o nome da reunião. Exemplo: /agenda acao:excluir titulo:Reunião Cliente"
    }
  }];
}

const inicio = new Date();
inicio.setMonth(inicio.getMonth() - 1);

const fim = new Date();
fim.setMonth(fim.getMonth() + 12);

return [{
  json: {
    ...$json,
    termo,
    inicio: inicio.toISOString(),
    fim: fim.toISOString()
  }
}];

const appId = $("Interpretar Comando").first().json.applicationId;
const token = $("Interpretar Comando").first().json.token;

const termo = ($("Preparar exclusão").first().json.termo || "")
  .toLowerCase()
  .trim();

const eventos = $input.all();

if (eventos.length === 0) {
  return [
    {
      json: {
        applicationId: appId,
        token,
        erro: true,
        resposta: "❌ Nenhum evento encontrado com esse nome na agenda nova.",
      },
    },
  ];
}

const filtrados = eventos.filter((item) => {
  const titulo = String(item.json.summary || "").toLowerCase();
  return !termo || titulo.includes(termo);
});

if (filtrados.length === 0) {
  return [
    {
      json: {
        applicationId: appId,
        token,
        erro: true,
        resposta: "❌ Nenhum evento encontrado com esse nome na agenda nova.",
      },
    },
  ];
}

if (filtrados.length > 1) {
  let texto =
    "⚠️ Encontrei mais de um evento. Use um nome mais específico:\n\n";

  filtrados.slice(0, 10).forEach((item, index) => {
    const ev = item.json;
    const titulo = ev.summary || "Sem título";
    const inicio = ev.start?.dateTime || ev.start?.date || "";
    texto += `${index + 1}. ${titulo} - ${inicio}\n`;
  });

  return [
    {
      json: {
        applicationId: appId,
        token,
        erro: true,
        resposta: texto,
      },
    },
  ];
}

const ev = filtrados[0].json;

return [
  {
    json: {
      applicationId: appId,
      token,
      erro: false,
      eventId: ev.id,
      titulo: ev.summary || "Sem título",
      resposta: `🗑️ Evento "${ev.summary || "Sem título"}" encontrado para exclusão.`,
    },
  },
];
